import { Link, useNavigate } from 'react-router-dom';

const Navbar = () => {
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  const handleLogout = () => {
    localStorage.removeItem('token');
    navigate('/login');
  };

  return (
    <nav className="bg-indigo-600 shadow-lg p-4">
      <div className="container mx-auto flex items-center justify-between">
        <Link to="/" className="text-white text-2xl font-bold tracking-tight hover:text-indigo-100 transition-colors">
          Study Assistant
        </Link>
        <div className="space-x-4">
          {!token ? (
            <>
              <Link to="/login" className="text-indigo-100 hover:text-white font-medium transition-colors">Login</Link>
              <Link to="/register" className="bg-white text-indigo-600 px-4 py-2 rounded-md font-semibold hover:bg-indigo-50 transition-colors">Register</Link>
            </>
          ) : (
            <button onClick={handleLogout} className="text-indigo-100 hover:text-white font-medium transition-colors">
              Logout
            </button>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
